var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......그래서 편입 첫날부터 학교에서 제일 비싼 장비를 때려 부쉈다는 말이로군.","JPN":"……というわけで、編入初日から学校で一番高い装置をぶち壊したってことか。","ENG":"So... that's why you broke the Academy's most expensive equipment on your first day here.","TWN":"所以說……你在入學第一天就砸掉了學校裡最貴的設備。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아하하...... 미안해. 선생님.","JPN":"ア、アハハ……ごめんね、先生。","ENG":"Ah... Hah hah... Sorry, Prof.","TWN":"啊，哈哈哈……真對不起，老師。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 혹시...... 이제 어떻게 되는 거야?","JPN":"ところで……これからどうなるの？","ENG":"By the way... What's going to happen to me now?","TWN":"那現在……會怎麼樣？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서, 설마 기계 값을 물어내라고 하진 않겠지?","JPN":"も、もしかして私が弁償することにはならないよね？","ENG":"Y-you're not going to make me pay for that machine, are you?","TWN":"不會讓我賠機器吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네에겐 다행스럽게도 배상 문제는 걱정하지 않아도 좋네.","JPN":"幸い、その辺は君が心配しなくてもいい。","ENG":"Luckily for you, you won't have to worry about compensating the Academy.","TWN":"你很幸運，不用擔心賠償的問題。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"학생들에게는 알리지 않았지만, 그건 사실 베타 테스트 용으로 설치된 장비거든.","JPN":"生徒には知られていないが、実はあの機械はベータテスト用の設備だ。","ENG":"Unbeknownst to the students, that equipment was actually set up for a beta test.","TWN":"雖然沒有跟學生們說，但其實安裝那台機器是為了進行最後測試。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"관리국의 엔지니어들이 시뮬레이터가 폭주를 일으켰단 소식에 아주 기뻐하더군.","JPN":"管理局のエンジニアたちはシミュレーターが暴走したという報告を受けて、とても喜んでいたらしい。","ENG":"The engineers over at the Administration were thrilled to hear about the system going overboard.","TWN":"管理局的工程師聽說模擬器暴走之後非常高興。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자기들이 예상 못한 버그를 찾아냈다고 말이야.","JPN":"予想できなかった不具合が見つかってよかったそうだ。","ENG":"Apparently you guys found a bug they didn't anticipate.","TWN":"說是我們發現了他們沒有預想到的缺陷。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 친구들도 염치가 있다면 학생에게 배상하라는 말은 못하겠지.","JPN":"あの人たちに良心があるのであれば、生徒に弁償などと言わないだろう。","ENG":"If anything, they're not so shameless to make you pay for helping them find the bug.","TWN":"他們還有良心的話，不會好意思讓學生賠償的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다, 다행이다......","JPN":"よ、よかった……","ENG":"Th-thank goodness...","TWN":"真、真是太好了……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"징계 위원회도 따로 열리진 않을 거다.","JPN":"懲戒委員会も開かれないだろう。","ENG":"There will not be a disciplinary hearing either.","TWN":"也不會召開懲戒委員會。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"원인이 뭐가 됐건 학생들의 안전을 위한 비상 행동이었으니까.","JPN":"原因が何であれ、生徒の安全のための行動だったからな。","ENG":"Regardless of the cause, your actions ensured the safety of the students.","TWN":"不管原因如何，你是為了學生們的安全才採取的緊急措施。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 다음에 또 이런 일이 벌어지면, 그때는 가급적 온건한 방식을 사용해 주면 좋겠군.","JPN":"しかし今度また同じようなことになったら、その時はできれば穏やかなやり方で解決してくれると助かる。","ENG":"But I hope you'll take a more subtle approach should anything like this happen again.","TWN":"但如果下次再發生這種事情，我希望你能用溫和一些的方法。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예를 들어 경찰을 부른다거나 말이지.","JPN":"例えば、警察を呼ぶとかな。","ENG":"Like calling the cops, for instance.","TWN":"比如叫警察。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"알겠나?","JPN":"わかったか？","ENG":"Understood?","TWN":"知道了嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마. 앞으로 시뮬레이터는 근처에도 안 갈 테니까.","JPN":"心配しないで。これからシミュレーターを使うつもりもないから。","ENG":"Don't worry. I'm not going anywhere near that simulator from now on.","TWN":"別擔心。我以後不會靠近模擬器的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말이 잘 통해서 좋군.","JPN":"物わかりの良い性格で助かる。","ENG":"I'm glad I could get through to you.","TWN":"那就好。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"약간의 불미스러운 일이 있었지만, 결과적으로 자네 실력만큼은 확실히 검증되었다고 해도 되겠지.","JPN":"多少のトラブルはあったが、結果的に君の実力は間違いないということが実証できたとも言える。","ENG":"Despite the minor hiccup, I guess this definitely proved what you're capable of.","TWN":"雖然發生了一些事情，但整體來說已經充分證明了你的實力。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"편입 직후라 어떻게 할지 고민했는데, 쓸데없는 짓이었어.","JPN":"編入直後だからどうしようか悩んだが、無駄な悩みだったな。","ENG":"We were trying to figure out how to test you right after your transfer, but I guess there was no point.","TWN":"我本來還擔心你剛來會無法適應，看來是我多想了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다음 주에 진행되는 다이브 실전 훈련에 자네도 참가하게 될 거다.","JPN":"来週実施されるダイブ実戦訓練には君も参加することになる。","ENG":"You'll be participating in real Dive training starting next week.","TWN":"現在看來，你可以直接參加下周的躍入實戰訓練。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다이브 실전 훈련?","JPN":"ダイブ実戦訓練？","ENG":"Dive training?","TWN":"躍入實戰訓練？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미가 이번에 처음 도입하는 훈련 과정이지.","JPN":"アカデミーが今回初めて導入する訓練だ。","ENG":"It's the first training program of its kind at the Academy.","TWN":"這是學院第一次導入的訓練課程。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"카운터라면 어떤 이유로든 이면세계에 가게 될 확률이 높아.","JPN":"カウンターならどんな理由であれ、いずれは裏世界に行くことになるだろう。","ENG":"So long as you're a Counter, you're bound to end up in the Counterside at some point.","TWN":"作為制裁者肯定免不了要去異界。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 이면세계는 위험한 곳이니, 저심도에서 미리 경험을 쌓게 하자는 논리지.","JPN":"だが裏世界はとても危険だから、低深度で先に経験を積んでおくという施策だ。","ENG":"But given the high risks present there, the program is meant to expose you to the environment at more shallow levels at first.","TWN":"但異界是危險的地方，所以需要在低深度累積經驗。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다이브 작전 경험자인 자네에겐 번거로운 일이겠지만......","JPN":"ダイブ作戦経験者である君にはただ面倒なことかもしれないが……","ENG":"I understand this may all feel like a hassle for someone with extensive Dive experiences like you...","TWN":"你做過躍入作戰，可能覺得不需要……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래도 다른 학생들은 자네를 보면서 많이 배울 수 있을 거다.","JPN":"他の生徒は君を見て、いろんなことが学べるはずだ。","ENG":"But I'm sure other students have much to learn from you.","TWN":"但其他學生可以透過這個對你進行觀察和學習。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그러면 언젠가 다시 이면세계로 갔을 때 학생들의 생존율도 조금은 올라가겠지.","JPN":"そうすればいつかまた裏世界に行った時、生徒たちの生存率も上がるだろう。","ENG":"That way, their chances of surviving their next trip to the Counterside should increase, at least a little.","TWN":"這樣帶領學生們真的去異界的時候，也能提高一些生存機率。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어떤가? 도와 주겠나?","JPN":"どうだ？　手を貸してくれないか？","ENG":"So how about it? Will you help us?","TWN":"怎麼樣？你願意幫忙嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아. 별로 어려운 부탁은 아니니까.","JPN":"いいよ。別に難しいことでもないから。","ENG":"Sure. It's not such a tough ask.","TWN":"沒問題，這又不難。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......내 실력으로 큰 도움이 될지는 모르겠지만.","JPN":"……私の力がそんなに役に立つかはわからないけどね。","ENG":"Although... I'm not sure how helpful I'll be.","TWN":"……但我不知道我能起到多大的幫助。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니. 이미 충분히 도움이 됐어.","JPN":"いや、十分だろう。","ENG":"Oh, no. You've proven to be most helpful already.","TWN":"不用想太多，你完全能勝任。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다이브 실전 훈련은 팀으로 진행될 예정이네.","JPN":"ダイブ実戦訓練はチームで行われる予定だ。","ENG":"The Dive training will take place in teams.","TWN":"躍入實戰訓練將會以小隊方式進行。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그러니 자네도 미리 마음이 맞는 팀원들을 만들어 두게나.","JPN":"だから君も、先に気の合うチームメンバーを探しておくように。","ENG":"So take the time now to recruit teammates you can trust.","TWN":"所以你最好提前找一些適合的小隊成員。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"아, 미나 후배. 여기야.","JPN":"あ、ミナ。ここだよ。","ENG":"Oh, hey Mina. Over here.","TWN":"哎，米娜同學，這裡。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어, 어떻게 됐어? 잘 끝났어?","JPN":"ど、どうなったの？　ちゃんと話せた？","ENG":"H-how did it go? Are you in trouble?","TWN":"怎麼樣？事情都解決了嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 그럭저럭. 특별한 징계는 없을 거래.","JPN":"まあね。特に罰もないって。","ENG":"It went okay. I won't be disciplined or anything.","TWN":"嗯，差不多吧。說是不會有什麼處罰。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정말?","JPN":"本当に？","ENG":"Really?","TWN":"真的？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"별일이네. 알렌 선생님은 엄청 원칙주의자라서 쉽게 넘어가지 않을 거라고 생각했는데......","JPN":"意外だね。アレン先生はすごい原則主義者だからただ事じゃ済まないと思ったのに……","ENG":"That's odd. I thought a stickler like Mr. Birmingham wouldn't let this go lightly...","TWN":"真是怪事。艾倫老師可是個原則主義，我以為你要吃點苦頭呢……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 좋은 분인 것 같던데?","JPN":"そう？　普通にいい人そうだったよ。","ENG":"Is that right? He seemed nice to me.","TWN":"是嗎？我感覺人很好啊？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러고 보니 레이 선배, 알렌 선생님이랑 먼 친척 관계라고 하지 않았어요?","JPN":"そういえばレイ先輩、アレン先生とは遠い親戚関係と言ってませんでした？","ENG":"Come to think of it, aren't you a distant cousin with Mr. Birmingham, Ray?","TWN":"對了，雷伊前輩，我聽說你與艾倫老師是遠房親戚？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"으, 응. 좀 엄하긴 해도 나쁜 사람은 아니야.","JPN":"う、うん。ちょっと厳しいところはあるけど、悪い人ではないよ。","ENG":"Y-yeah. He can be rather strict, but he's not a bad person.","TWN":"嗯，是啊。他雖然比較嚴格，但不是壞人。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"잘 모르는 사람이 많지만 의외로 자상하고 눈물도 많은 성격이거든.","JPN":"知られてないだけで、意外と優しくて涙もろい性格なんだ。","ENG":"A lot of people don't know this, but he can be surprisingly kind and emotional too.","TWN":"其實大家都不瞭解他，他性格很溫柔，還很容易哭呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에엑? 그 철혈의 알렌 선생님이?","JPN":"ええー？　あの冷血のアレン先生が？","ENG":"Huh? Are we talking about the same person?","TWN":"啊？那位冷血的艾倫老師嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"하하, 직접 보지 않으면 믿기 어렵긴 하지.","JPN":"ハハハ、直接見てないと信じがたいよね。","ENG":"Hah hah, I guess it's hard to believe until you see it yourself.","TWN":"哈哈，未曾親眼見過，的確是很難讓人相信的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 미나야, 다이브 실전 훈련 이야기는 들었어?","JPN":"ところでミナちゃん、ダイブ実戦訓練の話は聞いたの？","ENG":"By the way Mina, have you heard about the Dive training?","TWN":"對了，米娜，你聽說躍入實戰訓練了嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 다음주에 진행할 예정이라고 하던데.","JPN":"うん、来週やる予定って聞いたよ。","ENG":"Yeah, I heard it's scheduled for next week.","TWN":"嗯，據說會在下週進行。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 팀은? 누구랑 팀을 짤 건지는 정했어?","JPN":"チームは？　誰と組むか決めたの？","ENG":"What about your team? Have you decided on your teammates?","TWN":"那你決定跟誰組隊了嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아. 오늘 처음 등교했는데.","JPN":"そんなわけないでしょ。今日が初登校なのに。","ENG":"Of course not. I just got here today.","TWN":"我今天才第一天來學校，還沒有啦。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 우리는 어때? 나랑 레이 선배 말야.","JPN":"それじゃあ、私たちはどう？　私とレイ先輩ね。","ENG":"Then how about us? I mean me and Ray.","TWN":"那麼你覺得我們怎麼樣？我和雷伊前輩。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나까지?","JPN":"ぼ、僕も？","ENG":"M-me too?","TWN":"連、連我也？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"당연하죠. 어차피 레이 선배도 다른 친구는 없잖아요.","JPN":"そうですよ。どうせレイ先輩に他の友達はいないでしょう。","ENG":"Of course. It's not like you've got any other friends anyway, Ray.","TWN":"當然啦，反正雷伊前輩也沒有其他朋友。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이대로 있어 봤자 팀을 못 구한 사람들끼리 대충 모일 텐데.","JPN":"このままじゃチームが組めなかった人同士で適当に集まることになるから。","ENG":"Chances are you'll just end up teaming up with the other leftovers.","TWN":"反正到最後肯定是沒有找到隊伍的人隨便組隊。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러느니 그냥 우리랑 같이 하는 게 좋지 않아요?","JPN":"だったら私たちと一緒にやったほうがいいんじゃないですか？","ENG":"Wouldn't you prefer to team up with us instead?","TWN":"所以，不如我們一起組隊吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그렇긴 한데......","JPN":"た、確かにそうだけど……","ENG":"T-true...","TWN":"嗯……是這樣沒錯，但……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 사실은 조금 무서웠거든......","JPN":"実は私、ちょっと怖かったの……","ENG":"To be honest, I've been a bit intimidated by the Dive...","TWN":"我有些害怕……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아무리 훈련이라지만 이면세계는 위험한 곳이잖아.","JPN":"訓練とはいえ、裏世界は危険でしょう。","ENG":"I know it's just training, but the Counterside is still really dangerous.","TWN":"雖然只是訓練，但異界畢竟很危險。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 미나가 같이 가 준다면 안심이 될 것 같아.","JPN":"でもミナちゃんが一緒に居てくれるなら、安心できそう。","ENG":"But I think I'll feel much safer if you're by my side, Mina.","TWN":"有米娜在的話，我可能會安心一些。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"누가 뭐래도 나이엘 녀석 콧대를 납작하게 만들어 준 실력자잖아!","JPN":"何よりも、あの傲慢なナイエルの鼻をへし折ってやった実力者だもんね！","ENG":"Especially since I saw you put that Naielle jerk in her place!","TWN":"不管怎樣，你都是完勝奈爾的實力派，對吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 우리 같이 안 될까?","JPN":"だから一緒に行こう？","ENG":"So would you mind if we joined you?","TWN":"所以我們一起組隊怎麼樣？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 두 사람이라면 나도 괜찮아.","JPN":"いいよ、2人なら私も文句ない。","ENG":"Actually, I don't mind at all.","TWN":"嗯，如果是你們兩個的話，我沒問題。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아카데미에서 처음으로 사귄 친구들이잖아. 잘 부탁해.","JPN":"アカデミーで初めてできた友達だから。よろしくね。","ENG":"You're the first friends I've made at the Academy. It'd be my pleasure.","TWN":"你們是我來學院之後交的第一朋友。那麼請多多指教啦。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"좋았어! 그럼 매점으로 가자!","JPN":"よし！　それじゃ、売店に行こう！","ENG":"Fantastic! Then let's hit the snack bar!","TWN":"太棒了！去販賣部吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나 소대의 결성을 축하하는 의미로 음료수는 내가 살게!","JPN":"ミナ小隊結成のお祝いで私がジュースでも奢るね！","ENG":"We have to celebrate the birth of the Mina Squad! My treat!","TWN":"為了慶祝米娜小隊成立，我請大家喝飲料！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미, 미나 소대?!","JPN":"ミ、ミナ小隊！？","ENG":"M-Mina Squad?","TWN":"米、米娜小隊？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 원래 이런 데엔 리더 이름을 붙이는 거잖아?","JPN":"そう！　普通チームにはリーダーの名前をつけるでしょ？","ENG":"Yup! You're supposed to name these things after their leader, right?","TWN":"嗯！通常小隊都用隊長的名字命名，不是嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앞으로 많은 지도편달 부탁드립니다! 소대장!","JPN":"今後ともご指導ご鞭撻のほどよろしくお願いします、小隊長！","ENG":"I look forward to your sagacious guidance! Commander!","TWN":"那麼以後就請多多指教！小隊長！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐! 난 동의한 적 없어! 당장 다시 정해!!","JPN":"ま、待って！　私は同意してないから！　他の名前にして！！","ENG":"W-wait! I never agreed to this! You have to pick another name!","TWN":"等等！我可沒說要當隊長！重新選吧！！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나도 잘 부탁해, 미나 후배.","JPN":"ぼ、僕もよろしくね、ミナ。","ENG":"I-I think you'll make a great leader too, Mina.","TWN":"我、我也請你多指教！米娜同學。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......아니, 소대장님.","JPN":"……いや、小隊長。","ENG":"Uh, I mean... Commander.","TWN":"……哦不，小隊長。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};